mapper.select:
SELECT ml.maintenance_log_id AS maintenanceLogId, ml.equipment_id AS equipmentId, e.equipment_code AS equipmentCode, e.equipment_name AS equipmentName, ml.maintenance_item_standard_id AS maintenanceItemStandardId, mis.maintenance_item AS maintenanceItem, ml.maintenance_type AS maintenanceType, ml.maintenance_date AS maintenanceDate, ml.maintenance_score AS maintenanceScore, ml.eta_maint_delta AS etaMaintDelta, ml.maintenance_result AS maintenanceResult FROM maintenance_log ml INNER JOIN equipment e ON ml.equipment_id = e.equipment_id INNER JOIN maintenance_item_standard mis ON ml.maintenance_item_standard_id = mis.maintenance_item_standard_id WHERE 1 = 1
AND ml.equipment_id = #{equipmentId}
AND ml.maintenance_type = #{maintenanceType}
AND ml.maintenance_result = #{maintenanceResult}
ORDER BY ml.maintenance_log_id DESC
